const clone = value => JSON.parse(JSON.stringify(value));
const hashNumber = text => [...String(text)].reduce((a,c)=>((a*33)^c.charCodeAt(0))>>>0,5381);
const jstWeekKey = (date=new Date()) => {
  const d=new Date(date.getTime()+9*3600*1000);const day=(d.getUTCDay()+6)%7;d.setUTCDate(d.getUTCDate()-day);
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth()+1).padStart(2,'0')}-${String(d.getUTCDate()).padStart(2,'0')}`;
};
const weighted = entries => {
  const total=entries.reduce((a,x)=>a+Number(x.weight||1),0);let roll=cryptoFloat()*total;
  for(const x of entries){roll-=Number(x.weight||1);if(roll<=0)return x}return entries[entries.length-1];
};
const merge = (base,saved) => {
  if (!saved || typeof saved !== 'object') return clone(base);
  const out=Array.isArray(base)?[...saved]:{...base};
  for(const [k,v] of Object.entries(saved)){
    if(v&&typeof v==='object'&&!Array.isArray(v)&&base[k]&&typeof base[k]==='object'&&!Array.isArray(base[k]))out[k]=merge(base[k],v);else out[k]=v;
  }
  return out;
};

