// ---------- Poker evaluation shared by Hold'em ----------
const rankValue = rank => rank==='A'?14:rank==='K'?13:rank==='Q'?12:rank==='J'?11:Number(rank);
function evaluateFive(cards){
  const vals=cards.map(c=>rankValue(c.rank)).sort((a,b)=>b-a);const suits=new Set(cards.map(c=>c.suit));const counts=new Map();vals.forEach(v=>counts.set(v,(counts.get(v)||0)+1));
  const groups=[...counts.entries()].sort((a,b)=>b[1]-a[1]||b[0]-a[0]);const unique=[...new Set(vals)].sort((a,b)=>b-a);let straightHigh=0;
  if(unique.length===5){if(unique[0]-unique[4]===4)straightHigh=unique[0];else if(unique.join(',')==='14,5,4,3,2')straightHigh=5}
  const flush=suits.size===1;
  if(flush&&straightHigh)return{rank:8,name:straightHigh===14?'ROYAL FLUSH':'STRAIGHT FLUSH',tie:[straightHigh]};
  if(groups[0][1]===4)return{rank:7,name:'FOUR OF A KIND',tie:[groups[0][0],groups[1][0]]};
  if(groups[0][1]===3&&groups[1][1]===2)return{rank:6,name:'FULL HOUSE',tie:[groups[0][0],groups[1][0]]};
  if(flush)return{rank:5,name:'FLUSH',tie:vals};
  if(straightHigh)return{rank:4,name:'STRAIGHT',tie:[straightHigh]};
  if(groups[0][1]===3)return{rank:3,name:'THREE OF A KIND',tie:[groups[0][0],...groups.slice(1).map(x=>x[0]).sort((a,b)=>b-a)]};
  if(groups[0][1]===2&&groups[1][1]===2){const pairs=[groups[0][0],groups[1][0]].sort((a,b)=>b-a);return{rank:2,name:'TWO PAIR',tie:[...pairs,groups[2][0]]}}
  if(groups[0][1]===2)return{rank:1,name:'ONE PAIR',tie:[groups[0][0],...groups.slice(1).map(x=>x[0]).sort((a,b)=>b-a)]};
  return{rank:0,name:'HIGH CARD',tie:vals};
}
function compareHands(a,b){if(a.rank!==b.rank)return a.rank-b.rank;for(let i=0;i<Math.max(a.tie.length,b.tie.length);i++){const d=(a.tie[i]||0)-(b.tie[i]||0);if(d)return d}return 0}
function bestOfSeven(cards){let best=null;for(let a=0;a<cards.length-4;a++)for(let b=a+1;b<cards.length-3;b++)for(let c=b+1;c<cards.length-2;c++)for(let d=c+1;d<cards.length-1;d++)for(let e=d+1;e<cards.length;e++){const hand=evaluateFive([cards[a],cards[b],cards[c],cards[d],cards[e]]);if(!best||compareHands(hand,best)>0)best=hand}return best}

