  render(){if(!$('#bingoGrid',this.root))return;$('#bingoStatus',this.root).textContent=this.status;$('#bingoBet',this.root).textContent=formatL(this.bet);$('#bingoLast',this.root).textContent=this.draws.length?this.draws.at(-1):'—';$('#bingoCount',this.root).textContent=`${this.draws.length} / 35`;$('#bingoLines',this.root).textContent=this.lines.length;$('#bingoReturn',this.root).textContent=this.lines.length?`${this.lines.length} LINE COMPLETED`:'≤18 ×24 · ≤22 ×10 · ≤26 ×4 · ≤30 ×2 · ≤35 ×0.8';$('#bingoGrid',this.root).innerHTML=Array.from({length:5},(_,r)=>Array.from({length:5},(_,c)=>{const n=this.cellNumber(r,c),marked=this.marked.has(`${r}-${c}`);return`<div class="${marked?'marked':''} ${n==='FREE'?'free':''}" data-bingo-cell="${r}-${c}"><span>${n}</span></div>`}).join('')).join('');$('#bingoHistory',this.root).innerHTML=this.draws.slice(-20).reverse().map((n,i)=>`<span class="${i===0?'latest':''}">${n}</span>`).join('');$('#bingoDraw',this.root).disabled=this.busy;$('#bingoNew',this.root).disabled=this.busy;$$('[data-chip]',this.root).forEach(b=>{b.classList.toggle('active',Number(b.dataset.chip)===this.bet);b.disabled=this.busy})}
