class TowerGame extends GameBase {
  constructor(app,mount){super(app,mount);this.bet=500;this.active=false;this.floor=0;this.multiplier=1;this.traps=new Set();this.revealed=false;this.ward=0;this.wardFloorsGranted=new Set();this.status='BETを選んで塔へ入る'}
  mount(){this.root.innerHTML=`<div class="game-stage tower-stage eternal-game-stage"><div class="table-status"><b id="towerStatus">${this.status}</b><small>TEN FLOORS · TWO TRAPS PER FLOOR</small></div><div class="tower-danger-banner"><i>⚠</i><span><b>50% DANGER</b><small>4扉のうち2扉がTRAP</small></span><strong>2 SAFE / 2 TRAP</strong></div><div class="tower-scene"><div class="tower-progress"><small>FLOOR</small><strong id="towerFloor">0 / 10</strong><div>${Array.from({length:10},(_,i)=>`<i data-tower-step="${i+1}"></i>`).join('')}</div></div><div id="towerDoors" class="tower-doors">${Array.from({length:4},(_,i)=>`<button data-tower-door="${i}" type="button"><span>${['Ⅰ','Ⅱ','Ⅲ','Ⅳ'][i]}</span><b>SEALED</b><i>◇</i><small>UNKNOWN</small></button>`).join('')}</div><div class="tower-return-panel"><span><small>CURRENT RETURN</small><strong id="towerReturn">0 L</strong></span><span><small>MULTIPLIER</small><strong id="towerMulti">×1.00</strong></span><span><small>PROTECTION</small><em id="towerWard">NO WARD</em></span></div></div><div class="tower-actions"><button id="towerCash" class="table-button" type="button">CASH OUT</button><button id="towerStart" class="table-button primary" type="button">ENTER TOWER</button></div><div class="bet-dock eternal-bet-dock">${this.chipSelector(this.bet,null,[100,500,1000,2500,5000])}<div class="bet-readout"><small>ENTRY</small><strong id="towerBet">${formatL(this.bet)}</strong></div></div></div>`;this.bindChips(this.root,v=>{if(!this.active){this.bet=v;this.render()}});$$('[data-tower-door]',this.root).forEach(b=>b.addEventListener('click',()=>this.choose(Number(b.dataset.towerDoor))));$('#towerStart',this.root).addEventListener('click',()=>this.start());$('#towerCash',this.root).addEventListener('click',()=>this.cash());this.render()}
  start(){if(this.active||this.busy||!this.canAfford(this.bet)||!this.app.profile.spend(this.bet))return;this.active=true;this.floor=1;this.multiplier=1;this.ward=0;this.wardFloorsGranted.clear();this.status='2つの罠を避け、安全な扉を選択';this.prepare();this.render()}
  prepare(){this.traps=new Set(shuffled([0,1,2,3]).slice(0,2));this.revealed=false;if((this.floor===4||this.floor===7)&&!this.wardFloorsGranted.has(this.floor)){this.wardFloorsGranted.add(this.floor);this.ward=Math.max(this.ward,1)}}
  async choose(index){if(!this.active||this.busy||this.revealed)return;this.busy=true;this.revealed=true;this.render();await wait(this.app.profile.data.settings.reducedMotion?50:520);if(this.disposed)return;if(this.traps.has(index)){if(this.ward>0){this.ward--;this.status='WARDが罠を砕きました · 同じ階を再挑戦';this.app.audio.play('chime');await wait(this.app.profile.data.settings.reducedMotion?70:720);if(this.disposed)return;this.prepare();this.busy=false;this.render();return}this.status='THE TOWER CLAIMS THE RUN';this.app.recordRound({game:'tower',wager:this.bet,payout:0,label:'TOWER FALL',detail:`FLOOR ${this.floor} · 2 TRAPS`});this.active=false;this.app.audio.play('lose');this.busy=false;this.render();return}
    // Two traps doubles the risk. The return curve is rebalanced around the new 50% survival rate.
    this.multiplier*=1.62+this.floor*.03;this.app.audio.play('win');if(this.floor>=10){const payout=Math.floor(this.bet*this.multiplier*1.35);this.status='SUMMIT CONQUERED';this.app.eternal.data.stats.towerSummits++;this.app.recordRound({game:'tower',wager:this.bet,payout,label:'OBSIDIAN SUMMIT',detail:`×${(this.multiplier*1.35).toFixed(2)} · TWO TRAPS`,events:[{event:'towerSummit'}]});this.active=false;this.busy=false;this.render();return}this.floor++;this.status=`FLOOR ${this.floor} · 2 TRAPS · さらに登るかCASH OUT`;await wait(this.app.profile.data.settings.reducedMotion?40:520);if(this.disposed)return;this.prepare();this.busy=false;this.render()}
  cash(){if(!this.active||this.busy||this.floor<2)return;const payout=Math.floor(this.bet*this.multiplier);this.status=`CASH OUT · ${formatL(payout)}`;this.app.recordRound({game:'tower',wager:this.bet,payout,label:'TOWER CASH OUT',detail:`FLOOR ${this.floor} · ×${this.multiplier.toFixed(2)} · TWO TRAPS`});this.active=false;this.render()}
  render(){if(!$('#towerStatus',this.root))return;$('#towerStatus',this.root).textContent=this.status;$('#towerFloor',this.root).textContent=`${this.floor} / 10`;$('#towerBet',this.root).textContent=formatL(this.bet);$('#towerMulti',this.root).textContent=`×${this.multiplier.toFixed(2)}`;$('#towerReturn',this.root).textContent=this.active?formatL(this.bet*this.multiplier):'0 L';$('#towerWard',this.root).textContent=this.ward?`WARD ×${this.ward}`:'NO WARD';$$('[data-tower-step]',this.root).forEach(i=>{const n=Number(i.dataset.towerStep);i.classList.toggle('passed',n<this.floor);i.classList.toggle('current',n===this.floor&&this.active)});$$('[data-tower-door]',this.root).forEach(b=>{const idx=Number(b.dataset.towerDoor),trap=this.traps.has(idx);b.disabled=!this.active||this.busy||this.revealed;b.className=this.revealed?(trap?'trap':'safe'):'';b.querySelector('b').textContent=this.revealed?(trap?'TRAP':'SAFE'):'SEALED';b.querySelector('i').textContent=this.revealed?(trap?'✕':'✦'):'◇';b.querySelector('small').textContent=this.revealed?(trap?'ABYSS':'ASCEND'):'UNKNOWN'});$('#towerStart',this.root).disabled=this.active||this.busy;$('#towerCash',this.root).disabled=!this.active||this.busy||this.floor<2;$$('[data-chip]',this.root).forEach(b=>{b.classList.toggle('active',Number(b.dataset.chip)===this.bet);b.disabled=this.active})}
}

class ScratchGame extends GameBase {
  constructor(app,mount){super(app,mount);this.bet=500;this.active=false;this.resolved=false;this.symbols=[];this.revealed=new Set();this.canvas=null;this.ctx=null;this.cover=null;this.coverCtx=null;this.dpr=1;this.painting=false;this.lastPoint=null;this.strokes=[];this.resizeHandler=()=>this.resize();this.status='BETを選んで新しい星札を発行'}
  mount(){this.root.innerHTML=`<div class="game-stage scratch-stage eternal-game-stage"><div class="table-status"><b id="scratchStatus">${this.status}</b><small>FULL-SIZE SCRATCH · REAL SILVER MASK</small></div><div class="scratch-layout"><section class="scratch-ticket"><header><p class="eyebrow">MIDNIGHT ISSUE No. 09</p><h3>ROYAL SIGIL SCRATCH</h3><small>指またはマウスで銀膜を削る</small></header><div class="scratch-card"><canvas id="scratchCanvas" aria-label="削って遊ぶ大型スクラッチカード"></canvas><div class="scratch-progress"><span>REVEALED</span><b id="scratchProgress">0 / 9</b><i><u id="scratchProgressFill"></u></i></div></div><footer><span>同じ紋章を4つ以上集める</span><b id="scratchHint">ISSUE TICKETで開始</b></footer></section><aside class="scratch-paytable"><p class="eyebrow">SIGIL PAY TABLE</p><h4>同じ紋章を4つ以上</h4><div class="scratch-pay-list">${scratchSymbols.filter(x=>!['wild','blank'].includes(x.id)).map(x=>`<span><i>${x.icon}</i><b>${x.name}</b><em>4:${x.pay[4]}× · 5:${x.pay[5]}× · 6+:${x.pay[6]}×</em></span>`).join('')}</div><small>ASHはハズレ。WILDは各紋章へ代用され、最も高い配当だけを採用。9マスすべてを削るかREVEAL ALLで判定します。</small><div class="scratch-legend"><i>W</i><span><b>WILD</b><small>最高配当の紋章へ代用</small></span></div></aside></div><div class="scratch-actions"><button id="scratchReveal" class="table-button" type="button">REVEAL ALL</button><button id="scratchNew" class="table-button primary" type="button">ISSUE TICKET</button></div><div class="bet-dock eternal-bet-dock">${this.chipSelector(this.bet,null,[100,500,1000,2500,5000])}<div class="bet-readout"><small>TICKET</small><strong id="scratchBet">${formatL(this.bet)}</strong></div></div></div>`;this.canvas=$('#scratchCanvas',this.root);this.ctx=this.canvas.getContext('2d');this.cover=document.createElement('canvas');this.coverCtx=this.cover.getContext('2d',{willReadFrequently:true});this.bindChips(this.root,v=>{if(!this.active){this.bet=v;this.renderUi()}});$('#scratchNew',this.root).addEventListener('click',()=>this.issue());$('#scratchReveal',this.root).addEventListener('click',()=>this.revealAll());this.canvas.addEventListener('pointerdown',e=>this.startScratch(e));this.canvas.addEventListener('pointermove',e=>this.scratch(e));this.canvas.addEventListener('pointerup',e=>this.endScratch(e));this.canvas.addEventListener('pointercancel',e=>this.endScratch(e));window.addEventListener('resize',this.resizeHandler,{passive:true});this.resize();this.renderUi()}
  unmount(){window.removeEventListener('resize',this.resizeHandler);super.unmount()}
  issue(){if(this.active||!this.canAfford(this.bet)||!this.app.profile.spend(this.bet))return;this.active=true;this.resolved=false;this.revealed.clear();this.strokes=[];this.symbols=Array.from({length:9},()=>weighted(scratchSymbols));this.status='銀膜を削って9つの紋章を公開';this.resize(true);this.app.audio.play('deal');this.renderUi()}
  geometry(){const w=this.canvas.width/this.dpr,h=this.canvas.height/this.dpr,pad=Math.max(24,w*.045),top=Math.max(58,w*.075),gap=Math.max(9,w*.014),bottom=Math.max(27,w*.04),cw=(w-pad*2-gap*2)/3,ch=(h-top-bottom-gap*2)/3;return{w,h,pad,top,gap,bottom,cw,ch}}
  cellRect(i,g=this.geometry()){const c=i%3,r=Math.floor(i/3);return{x:g.pad+c*(g.cw+g.gap),y:g.top+r*(g.ch+g.gap),w:g.cw,h:g.ch}}
  resize(forceCover=false){if(!this.canvas)return;const rect=this.canvas.getBoundingClientRect(),cssW=Math.max(340,Math.round(rect.width||760)),cssH=Math.round(cssW*.70);this.dpr=Math.min(devicePixelRatio||1,2);const pw=Math.round(cssW*this.dpr),ph=Math.round(cssH*this.dpr);const changed=this.canvas.width!==pw||this.canvas.height!==ph;if(changed){this.canvas.width=pw;this.canvas.height=ph;this.cover.width=pw;this.cover.height=ph;this.canvas.style.height=`${cssH}px`;this.ctx.setTransform(this.dpr,0,0,this.dpr,0,0);this.coverCtx.setTransform(this.dpr,0,0,this.dpr,0,0)}if(changed||forceCover)this.buildCover();this.drawTicket()}
  buildCover(){if(!this.coverCtx)return;const ctx=this.coverCtx,g=this.geometry();ctx.clearRect(0,0,g.w,g.h);for(let i=0;i<9;i++){if(this.revealed.has(i))continue;const r=this.cellRect(i,g),cover=ctx.createLinearGradient(r.x,r.y,r.x+r.w,r.y+r.h);cover.addColorStop(0,'#f4f1f2');cover.addColorStop(.23,'#77737d');cover.addColorStop(.48,'#dad6da');cover.addColorStop(.72,'#8d8992');cover.addColorStop(1,'#efedef');ctx.fillStyle=cover;ctx.fillRect(r.x,r.y,r.w,r.h);ctx.strokeStyle='rgba(255,255,255,.56)';ctx.lineWidth=1;for(let y=r.y+8;y<r.y+r.h;y+=9){ctx.beginPath();ctx.moveTo(r.x,y);ctx.lineTo(r.x+r.w,y);ctx.stroke()}ctx.fillStyle='rgba(38,31,46,.55)';ctx.font=`700 ${Math.max(10,r.w*.078)}px sans-serif`;ctx.textAlign='center';ctx.fillText('SCRATCH',r.x+r.w/2,r.y+r.h*.55)}ctx.save();ctx.globalCompositeOperation='destination-out';for(const p of this.strokes){ctx.beginPath();ctx.arc(p.x*g.w,p.y*g.h,p.r*Math.min(g.w,g.h),0,Math.PI*2);ctx.fill()}ctx.restore();for(const i of this.revealed){const r=this.cellRect(i,g);ctx.clearRect(r.x-1,r.y-1,r.w+2,r.h+2)}}
  drawTicket(){if(!this.ctx)return;const ctx=this.ctx,g=this.geometry();ctx.clearRect(0,0,g.w,g.h);const bg=ctx.createLinearGradient(0,0,g.w,g.h);bg.addColorStop(0,'#160b29');bg.addColorStop(.48,'#5a2869');bg.addColorStop(1,'#0d0717');ctx.fillStyle=bg;ctx.fillRect(0,0,g.w,g.h);ctx.strokeStyle='rgba(239,200,105,.78)';ctx.lineWidth=3;ctx.strokeRect(9,9,g.w-18,g.h-18);ctx.fillStyle='#f0d486';ctx.font=`700 ${Math.max(13,g.w*.025)}px Georgia`;ctx.textAlign='center';ctx.fillText('MIDNIGHT SCRATCH · NINE SEALED SIGILS',g.w/2,34);for(let i=0;i<9;i++){const r=this.cellRect(i,g),sym=this.symbols[i];const cell=ctx.createRadialGradient(r.x+r.w*.5,r.y+r.h*.35,2,r.x+r.w*.5,r.y+r.h*.5,r.w*.7);cell.addColorStop(0,'rgba(111,57,132,.66)');cell.addColorStop(1,'rgba(6,3,12,.86)');ctx.fillStyle=cell;ctx.fillRect(r.x,r.y,r.w,r.h);ctx.strokeStyle=this.revealed.has(i)?'rgba(244,211,130,.8)':'rgba(239,200,105,.24)';ctx.lineWidth=this.revealed.has(i)?2:1;ctx.strokeRect(r.x+.5,r.y+.5,r.w-1,r.h-1);ctx.fillStyle='#f5d98f';ctx.shadowBlur=18;ctx.shadowColor='rgba(228,176,82,.25)';ctx.font=`700 ${Math.min(r.w,r.h)*.44}px Georgia`;ctx.fillText(sym?sym.icon:'✦',r.x+r.w/2,r.y+r.h*.58);ctx.shadowBlur=0;ctx.fillStyle='#aa96ad';ctx.font=`700 ${Math.max(8,r.w*.065)}px sans-serif`;ctx.fillText(sym?sym.name:'SEALED',r.x+r.w/2,r.y+r.h*.82)}if(this.active&&!this.resolved)ctx.drawImage(this.cover,0,0,this.cover.width,this.cover.height,0,0,g.w,g.h)}
  point(e){const rect=this.canvas.getBoundingClientRect(),g=this.geometry();return{x:(e.clientX-rect.left)/rect.width*g.w,y:(e.clientY-rect.top)/rect.height*g.h}}
  cellAtPoint(p){const g=this.geometry();for(let i=0;i<9;i++){const r=this.cellRect(i,g);if(p.x>=r.x&&p.x<=r.x+r.w&&p.y>=r.y&&p.y<=r.y+r.h)return i}return-1}
  startScratch(e){if(!this.active||this.resolved)return;this.painting=true;this.lastPoint=this.point(e);this.canvas.setPointerCapture?.(e.pointerId);this.scratch(e)}
  endScratch(e){this.painting=false;this.lastPoint=null;try{this.canvas.releasePointerCapture?.(e.pointerId)}catch{}}
  scratch(e){if(!this.painting||!this.active||this.resolved)return;e.preventDefault();const p=this.point(e),g=this.geometry(),last=this.lastPoint||p,dist=Math.hypot(p.x-last.x,p.y-last.y),steps=Math.max(1,Math.ceil(dist/12)),radius=Math.max(18,Math.min(g.cw,g.ch)*.16);this.coverCtx.save();this.coverCtx.globalCompositeOperation='destination-out';for(let n=0;n<=steps;n++){const t=n/steps,x=last.x+(p.x-last.x)*t,y=last.y+(p.y-last.y)*t;this.coverCtx.beginPath();this.coverCtx.arc(x,y,radius,0,Math.PI*2);this.coverCtx.fill();this.strokes.push({x:x/g.w,y:y/g.h,r:radius/Math.min(g.w,g.h)})}this.coverCtx.restore();this.lastPoint=p;const i=this.cellAtPoint(p);if(i>=0&&!this.revealed.has(i)&&this.coverage(i)>=.48){this.revealed.add(i);const r=this.cellRect(i,g);this.coverCtx.clearRect(r.x-1,r.y-1,r.w+2,r.h+2);this.app.audio.play('chime')}else this.app.audio.play('click');this.drawTicket();this.renderProgress();if(this.revealed.size>=9)this.resolve()}
  coverage(i){const g=this.geometry(),r=this.cellRect(i,g),scale=this.dpr,x=Math.max(0,Math.floor((r.x+4)*scale)),y=Math.max(0,Math.floor((r.y+4)*scale)),w=Math.max(1,Math.floor((r.w-8)*scale)),h=Math.max(1,Math.floor((r.h-8)*scale)),data=this.coverCtx.getImageData(x,y,w,h).data;let transparent=0,total=0;const stride=Math.max(1,Math.floor(5*scale));for(let yy=0;yy<h;yy+=stride)for(let xx=0;xx<w;xx+=stride){total++;if(data[(yy*w+xx)*4+3]<40)transparent++}return total?transparent/total:0}
  revealAll(){if(!this.active||this.resolved)return;for(let i=0;i<9;i++)this.revealed.add(i);this.coverCtx.clearRect(0,0,this.cover.width,this.cover.height);this.drawTicket();this.renderProgress();this.resolve()}
  resolve(){if(this.resolved)return;this.resolved=true;for(let i=0;i<9;i++)this.revealed.add(i);const counts={};let wild=0;for(const s of this.symbols){if(s.id==='wild')wild++;else if(s.id!=='blank')counts[s.id]=(counts[s.id]||0)+1}let best={sym:null,count:0,multi:0};for(const sym of scratchSymbols.filter(x=>x.pay)){const count=(counts[sym.id]||0)+wild,multi=scratchPay(sym,count);if(multi>best.multi)best={sym,count,multi}}const {sym,count,multi}=best,payout=Math.floor(this.bet*multi);this.status=multi?`${sym.name} ×${count} · ${formatL(payout)} RETURN`:'NO MATCH · 次の星札へ';if(multi)this.app.eternal.data.stats.scratchWins++;this.app.recordRound({game:'scratch',wager:this.bet,payout,label:multi?'MIDNIGHT SCRATCH WIN':'SCRATCH RESULT',detail:multi?`${sym.name} ×${count}`:'NO MATCH',events:multi?[{event:'scratchWin'}]:[]});this.active=false;this.drawTicket();this.renderUi()}
  renderProgress(){if(!$('#scratchProgress',this.root))return;const n=this.revealed.size;$('#scratchProgress',this.root).textContent=`${n} / 9`;$('#scratchProgressFill',this.root).style.width=`${n/9*100}%`;$('#scratchHint',this.root).textContent=this.active?`${n} / 9 SIGILS REVEALED`:this.resolved?'RESULT COMPLETE':'ISSUE TICKETで開始'}
  renderUi(){if(!$('#scratchStatus',this.root))return;$('#scratchStatus',this.root).textContent=this.status;$('#scratchBet',this.root).textContent=formatL(this.bet);$('#scratchNew',this.root).disabled=this.active;$('#scratchReveal',this.root).disabled=!this.active||this.resolved;$$('[data-chip]',this.root).forEach(b=>{b.classList.toggle('active',Number(b.dataset.chip)===this.bet);b.disabled=this.active});this.renderProgress()}
}


const NEW_GAME_CLASSES = {holdem:HoldemGame,war:WarGame,bingo:BingoGame,tower:TowerGame,scratch:ScratchGame};

function eternalGameCards(){return `
  <button class="game-card eternal-game-card holdem-game-card" data-game="holdem" type="button"><div class="game-art eternal-card-art holdem-art"><div class="he-card one">A♠</div><div class="he-card two">K♠</div><div class="he-board"><i>Q♠</i><i>J♠</i><i>10♠</i></div></div><div class="game-copy"><span class="game-tag">COMMUNITY CARDS</span><h4>ECLIPSE<br />HOLD'EM</h4><p>FLOPを見てCALLかFOLD。最強の5枚役でHOUSEへ挑め。</p><div><b>ANTE 100 L〜</b><i>PLAY →</i></div></div></button>
  <button class="game-card eternal-game-card war-game-card" data-game="war" type="button"><div class="game-art eternal-card-art war-art"><div class="war-blade left">A</div><b>⚔</b><div class="war-blade right">K</div></div><div class="game-copy"><span class="game-tag">ONE CARD DUEL</span><h4>CROWN<br />WAR</h4><p>一枚で決まる。TIEなら退くか、さらにWARへ進むか。</p><div><b>BET 100 L〜</b><i>PLAY →</i></div></div></button>
  <button class="game-card eternal-game-card bingo-game-card" data-game="bingo" type="button"><div class="game-art eternal-card-art bingo-art"><div class="bingo-mini">${Array.from({length:25},(_,i)=>`<i class="${[2,6,12,18,22].includes(i)?'hit':''}">${i===12?'★':(i*7)%75+1}</i>`).join('')}</div><span>BINGO</span></div><div class="game-copy"><span class="game-tag">75 BALL SPEED</span><h4>LUNAR<br />BINGO</h4><p>月球を読み上げ、早いライン完成ほど巨大配当。</p><div><b>TICKET 100 L〜</b><i>PLAY →</i></div></div></button>
  <button class="game-card eternal-game-card tower-game-card" data-game="tower" type="button"><div class="game-art eternal-card-art tower-art"><div class="tower-mini"><i></i><i></i><i></i><i></i><i></i></div><b>♜</b><span>FLOOR 10</span></div><div class="game-copy"><span class="game-tag">PUSH YOUR LUCK</span><h4>OBSIDIAN<br />TOWER</h4><p>安全な扉を選び、倍率を積み上げて頂上を目指せ。</p><div><b>ENTRY 100 L〜</b><i>PLAY →</i></div></div></button>
  <button class="game-card eternal-game-card scratch-game-card" data-game="scratch" type="button"><div class="game-art eternal-card-art scratch-art"><div class="scratch-mini"><i>?</i><i>♛</i><i>?</i><i>✦</i><i>?</i><i>☾</i><i>?</i><i>?</i><i>♦</i></div><span>SCRATCH</span></div><div class="game-copy"><span class="game-tag">TOUCH REVEAL</span><h4>MIDNIGHT<br />SCRATCH</h4><p>銀膜を指で削り、同じ紋章を4つ以上呼び覚ませ。</p><div><b>TICKET 100 L〜</b><i>PLAY →</i></div></div></button>`}

function eternalModalHtml(){return `<section id="eternalModal" class="modal palace-modal wide-modal eternal-modal" hidden aria-modal="true" role="dialog"><button class="modal-close" data-close-eternal type="button">×</button><div class="modal-crest">♛</div><p class="eyebrow">ETERNAL CROWN · PALACE LEGACY</p><h2>永夜王冠庁</h2><div class="eternal-tabs"><button data-eternal-tab="legacy" class="active" type="button">王名と能力</button><button data-eternal-tab="odyssey" type="button">PALACE ODYSSEY</button><button data-eternal-tab="dealers" type="button">ディーラー絆</button><button data-eternal-tab="artifacts" type="button">秘宝48</button><button data-eternal-tab="league" type="button">NIGHT LEAGUE</button></div><div id="eternalContent"></div></section>`}

class EternalSystem {
  constructor(app){this.app=app;this.tab='legacy';this.ensureData();this.injectUi();this.bind();this.patchCore();this.updateAll();this.syncTimer=setInterval(()=>this.syncLeague(),18000);this.syncLeague()}
  get data(){return this.app.profile.data.eternal}
  get odyssey(){return this.data.odyssey}
  ensureData(){const fresh=defaultEternal();this.app.profile.data.eternal=merge(fresh,this.app.profile.data.eternal||{});const d=this.data;d.version=ETERNAL_VERSION;if(d.league.week!==jstWeekKey())d.league={week:jstWeekKey(),score:0,rounds:0,wins:0,bestReturn:0,rank:0,board:[],lastSync:0};for(const district of DISTRICTS)d.districts[district.id]=merge({level:1,xp:0,rounds:0,wins:0},d.districts[district.id]||{});for(const dealer of DEALERS)d.dealers[dealer.id]=merge({level:1,xp:0,rounds:0,chapters:1},d.dealers[dealer.id]||{});if(this.app.ascension?.data?.mastery){for(const game of ALL_GAME_IDS)this.app.ascension.data.mastery[game]=merge({level:1,xp:0,rounds:0,wins:0,best:0},this.app.ascension.data.mastery[game]||{})}this.app.profile.save()}
  injectUi(){document.title='LUX NOCTIS ETERNAL CROWN — 18 Games & Live PvP';const head=document.querySelector('head');if(!document.querySelector('link[href="eternal.css"]')&&!document.getElementById('eternalInlineStyles')){const link=document.createElement('link');link.rel='stylesheet';link.href='eternal.css';head.appendChild(link)}const count=$('.games-section .section-heading > span');if(count)count.textContent='18 GAMES · ODYSSEY · 5 LIVE PVP MODES';const grid=$('#gameGrid');if(grid&&!grid.querySelector('[data-game="holdem"]'))grid.insertAdjacentHTML('beforeend',eternalGameCards());const asc=$('#ascensionRibbon');if(asc&&!$('#eternalRibbon'))asc.insertAdjacentHTML('afterend',`<section id="eternalRibbon" class="eternal-ribbon"><button id="legacyButton" type="button"><i>♛</i><span><small>PALACE RENOWN</small><b id="renownRibbon">Lv.1</b></span><em><u id="renownRibbonFill"></u></em></button><button id="odysseyButton" type="button"><i>♜</i><span><small>PALACE ODYSSEY</small><b id="odysseyRibbon">READY</b></span></button><button id="bondButton" type="button"><i>☾</i><span><small>DEALER BONDS</small><b id="bondRibbon">8 DEALERS</b></span></button><button id="artifactButton" type="button"><i>◆</i><span><small>ETERNAL ARTIFACTS</small><b id="artifactRibbon">0 / 48</b></span></button><button id="leagueButton" type="button"><i>⚔</i><span><small>NIGHT LEAGUE</small><b id="leagueRibbon">0 PTS</b></span></button></section><button id="eternalOmenBar" class="eternal-omen-bar" type="button"><i id="eternalOmenIcon">✦</i><span><small>GRAND PALACE OMEN</small><b id="eternalOmenName">次の大兆候まで 8 ROUND</b><em id="eternalOmenDesc">成長、蒐集、遠征、リーグを強化する特別な夜。</em></span><strong id="eternalOmenRounds">8</strong></button>`);const sidebar=$('.lobby-sidebar');if(sidebar&&!$('#leaguePanel'))sidebar.insertAdjacentHTML('beforeend',`<section id="leaguePanel" class="glass-panel league-panel"><div class="panel-title"><div><p class="eyebrow">ROOM NIGHT LEAGUE</p><h3>今週の王座争い</h3></div><button id="leaguePanelOpen" class="tiny-button" type="button">⚔</button></div><div id="leaguePodium" class="league-podium"><span>同期中…</span></div><div class="league-self"><small>YOUR SCORE</small><strong id="leagueSelfScore">0</strong><b id="leagueSelfRank">#—</b></div></section>`);const toast=$('#toastStack');if(toast&&!$('#eternalModal'))toast.insertAdjacentHTML('beforebegin',eternalModalHtml());const profileTabs=$('#profileModal .modal-tabs');if(profileTabs&&!profileTabs.querySelector('[data-profile-tab="legacy"]'))profileTabs.insertAdjacentHTML('beforeend','<button data-profile-tab="legacy" type="button">永夜王冠</button>');$('.intro-copy .eyebrow').textContent='ETERNAL CROWN · 18 TABLES · 5 LIVE PVP MODES';$('.brand-text small').textContent='ETERNAL CROWN · SOCIAL CASINO';$('.intro-copy .intro-lead').innerHTML='18のゲーム、120の蒐集品、能力星座、協力レイド、周回型PALACE ODYSSEY。<br />友達とは5種類のリアルタイムCROWN DUELで対戦。';const hero=$('.hero-copy > p:not(.eyebrow)');if(hero)hero.textContent='18テーブル、永夜王名、ディーラーとの絆、48の追加秘宝、周回遠征、5種類のライブPvP。すべてプレイコイン専用です。';$$('.eternal-game-card').forEach(b=>b.addEventListener('click',()=>this.app.openGame(b.dataset.game)))}
  bind(){const buttons={legacy:'legacyButton',odyssey:'odysseyButton',dealers:'bondButton',artifacts:'artifactButton',league:'leagueButton'};Object.entries(buttons).forEach(([tab,id])=>$(`#${id}`)?.addEventListener('click',()=>this.open(tab)));$('#leaguePanelOpen')?.addEventListener('click',()=>this.open('league'));$('#eternalOmenBar')?.addEventListener('click',()=>this.open('legacy'));$$('[data-eternal-tab]').forEach(b=>b.addEventListener('click',()=>this.render(b.dataset.eternalTab)));$$('[data-close-eternal]').forEach(b=>b.addEventListener('click',()=>this.app.closeModal()));$$('#profileModal [data-profile-tab]').forEach(b=>b.addEventListener('click',()=>{if(b.dataset.profileTab==='legacy'){ $$('#profileModal [data-profile-tab]').forEach(x=>x.classList.toggle('active',x===b));this.app.renderProfile('legacy')}}))}
  patchCore(){const originalRecord=CasinoApp.prototype.recordRound;const self=this;CasinoApp.prototype.recordRound=function(payload){const net=originalRecord.call(this,payload);this.eternal?.onRound({...payload,net});return net};const originalOpen=CasinoApp.prototype.openGame;CasinoApp.prototype.openGame=function(id){if(!NEW_GAME_CLASSES[id])return originalOpen.call(this,id);this.closeModal();this.gameInstance?.unmount?.();this.currentGame=id;this.profile.data.lastGame=id;this.profile.save();const m=this.gameMeta(id);$('#gameEyebrow').textContent=m.eyebrow;$('#gameTitle').textContent=m.title;$('#gameMount').innerHTML='';this.showScreen('gameScreen');const activeScreen=$('#gameScreen');if(activeScreen)activeScreen.scrollTop=0;this.updateMobileNav('');this.gameInstance=new NEW_GAME_CLASSES[id](this,$('#gameMount'));this.gameInstance.mount();this.room.presence();this.audio.play('chime');this.updateNightEventUi();this.eternal?.updateAll()};const originalReset=ProfileStore.prototype.reset;ProfileStore.prototype.reset=function(name){originalReset.call(this,name);this.data.eternal=defaultEternal();this.save();if(this.app.eternal){this.app.eternal.ensureData();this.app.eternal.updateAll()}};const originalHud=CasinoApp.prototype.updateHud;CasinoApp.prototype.updateHud=function(){originalHud.call(this);this.eternal?.updateAll()};const originalProfile=CasinoApp.prototype.renderProfile;CasinoApp.prototype.renderProfile=function(tab='stats'){if(tab==='legacy'&&this.eternal){const p=this.profile.data,r=this.profile.rank();$('#profileAvatar').textContent=this.avatarGlyph();$('#profileName').textContent=p.name;$('#profileRank').textContent=`${r.name} · Lv.${p.level}`;$('#profileBalance').textContent=fmt.format(p.balance);this.eternal.renderProfile($('#profileTabContent'));return}return originalProfile.call(this,tab)};const originalTicker=CasinoApp.prototype.updateTicker;CasinoApp.prototype.updateTicker=function(){const event=this.activeNightEvent?.(),festival=this.ascension?.festival?.(),omen=this.eternal?.omen?.();const local=[`<span><b>ETERNAL CROWN</b> 18ゲーム・120種蒐集・周回遠征</span>`,`<span><b>5 LIVE PVP</b> ROULETTE・DICE・BLACKJACK・WAR・BACCARAT</span>`,`<span><b>PALACE ODYSSEY</b> 12階の分岐型ローグライク遠征</span>`,`<span><b>NIGHT LEAGUE</b> 同じROOMで週間王座を競う</span>`,omen?`<span><b>${omen.name}</b> ${omen.desc}</span>`:'',festival?`<span><b>${festival.name}</b> ${festival.desc}</span>`:'',event?`<span><b>${event.name}</b> ${event.desc}</span>`:`<span><b>PLAY MONEY</b> 購入・換金・譲渡はできません</span>`].filter(Boolean);const room=(this.room?.feed||[]).slice(0,5).map(x=>`<span>${x.html||escapeHtml(x.text||'')}</span>`);const ticker=$('#liveTicker');if(ticker)ticker.innerHTML=[...room,...local,...room,...local].join('')};const originalHandle=RoomClient.prototype.handle;RoomClient.prototype.handle=function(msg){originalHandle.call(this,msg);if(msg.league)this.app.eternal?.receiveLeague(msg.league)};this.app.eternal=this;window.__LUX_ETERNAL__=this}
  talentEffect(key){let value=0;for(const node of TALENT_NODES){const rank=Number(this.data.renown.nodes[node.id]||0);if(node.effect===key)value+=rank*node.amount}return value}
  omen(){return OMENS.find(x=>x.id===this.data.omen.active)||null}
  omenEffect(key){return Number(this.omen()?.effect?.[key]||0)}
  renownNeed(level=this.data.renown.level){return 260+level*115}
  districtNeed(level){return 180+level*95}
  dealerNeed(level){return 90+level*55}
  addRenown(amount){let gain=Math.max(0,Math.floor(amount));gain=Math.floor(gain*(1+this.talentEffect('renown')+this.omenEffect('renown')));this.data.renown.xp+=gain;this.data.renown.totalXp+=gain;let levels=0;while(this.data.renown.level<100&&this.data.renown.xp>=this.renownNeed()){this.data.renown.xp-=this.renownNeed();this.data.renown.level++;levels++;if(this.data.renown.level%4===0)this.data.renown.points++}if(levels){this.app.audio.play('chime');this.app.toast('PALACE RENOWN UP',`王名 Lv.${this.data.renown.level} · 能力点 ${this.data.renown.points}`,'♛');this.app.celebration.burst(.45)}return gain}
  addDistrict(game,amount,win){const district=DISTRICTS.find(d=>d.games.includes(game));if(!district)return;const d=this.data.districts[district.id];d.xp+=Math.max(1,Math.floor(amount));d.rounds++;if(win)d.wins++;while(d.level<30&&d.xp>=this.districtNeed(d.level)){d.xp-=this.districtNeed(d.level);d.level++;if(d.level%5===0){this.data.keys++;this.app.toast('DISTRICT MASTERY',`${district.jp} Lv.${d.level} · ETERNAL KEY +1`,district.icon)}}}
  addBond(game,wager,win){const dealer=DEALERS.find(d=>d.games.includes(game));if(!dealer)return;const state=this.data.dealers[dealer.id];let gain=12+Math.floor(wager/1200)+(win?10:0);gain=Math.floor(gain*(1+this.talentEffect('bond')+this.omenEffect('bond')));state.xp+=gain;state.rounds++;while(state.level<10&&state.xp>=this.dealerNeed(state.level)){state.xp-=this.dealerNeed(state.level);state.level++;state.chapters=Math.max(state.chapters,Math.ceil(state.level/2));this.app.toast('DEALER BOND UP',`${dealer.jp} · BOND Lv.${state.level}`,dealer.icon);if(state.level===10){this.data.keys++;this.app.celebration.burst(.35)}}}
  artifactDropChance(){return .035+this.talentEffect('artifact')+this.omenEffect('artifact')}
  rarityForArtifact(){return weighted(RARITIES)}
  grantArtifact(forcedRarity=null,notify=true){const rarity=forcedRarity||this.rarityForArtifact().id;let pool=ETERNAL_ARTIFACTS.filter(x=>x.rarity===rarity&&!this.data.artifacts.owned[x.id]);if(!pool.length)pool=ETERNAL_ARTIFACTS.filter(x=>!this.data.artifacts.owned[x.id]);if(!pool.length){this.data.artifacts.shards+=250;return null}const item=choice(pool);this.data.artifacts.owned[item.id]=Date.now();this.data.artifacts.last=item.id;this.data.stats.artifactsFound++;this.updateSet(item.set);if(notify){this.app.toast('ETERNAL ARTIFACT 発見',`${item.name} · ${item.rarity.toUpperCase()}`,item.icon);this.app.audio.play('chime');this.app.celebration.burst(.3)}return item}
  updateSet(setId){const owned=ETERNAL_ARTIFACTS.filter(x=>x.set===setId&&this.data.artifacts.owned[x.id]).length;this.data.artifacts.sets[setId]=owned;if(owned===6&&!this.data.artifacts.sets[`${setId}-claimed`]){this.data.artifacts.sets[`${setId}-claimed`]=true;this.data.keys+=2;const paid=this.app.profile.credit(4000,'collection');const set=ARTIFACT_SETS.find(x=>x.id===setId);if(paid>0)this.app.bigWin(paid,'ARTIFACT SET COMPLETE',`${set.jp}${paid<4000?' · 残額NOTES':''}`);else this.app.toast('ARTIFACT SET COMPLETE',`${set.jp} · L報酬はCROWN NOTESへ変換されました。`,'◆')}}
  openArtifactVault(){if(this.data.keys<1)return this.app.toast('ETERNAL KEYが必要です','ODYSSEY、熟練、イベントで獲得できます。','◇');this.data.keys--;this.data.artifacts.opened++;const drops=[];for(let i=0;i<3;i++){const rarity=i===2&&cryptoFloat()<.2?'legendary':null;const item=this.grantArtifact(rarity,false);if(item)drops.push(item)}this.app.profile.save();this.render('artifacts');this.app.audio.play('bigwin');this.app.celebration.burst(.6);this.app.toast('ETERNAL VAULT OPEN',drops.length?drops.map(x=>x.name).join(' · '):'全秘宝完成ボーナス','◆')}
  craftArtifact(){if(this.data.artifacts.shards<400)return this.app.toast('秘宝片が足りません','400 SHARDSで未所持の秘宝を錬成できます。','◆');const pool=ETERNAL_ARTIFACTS.filter(x=>!this.data.artifacts.owned[x.id]);if(!pool.length)return;this.data.artifacts.shards-=400;const item=choice(pool);this.data.artifacts.owned[item.id]=Date.now();this.updateSet(item.set);this.app.profile.save();this.render('artifacts');this.app.toast('秘宝錬成 完了',item.name,item.icon)}
  advanceOmen(){const st=this.data.omen;if(st.active){st.remaining--;if(st.remaining<=0){const ended=this.omen();st.active=null;st.nextIn=6+randomInt(5);this.app.toast('大兆候が静まりました',ended?.jp||'GRAND OMEN','☾')}}else{st.nextIn--;if(st.nextIn<=0){const omen=choice(OMENS);st.active=omen.id;st.remaining=omen.rounds;this.app.toast('GRAND PALACE OMEN',`${omen.jp} — ${omen.desc}`,omen.icon);this.app.celebration.burst(.25)}}}
  onRound({game,wager=0,payout=0,net=0}){if(!ALL_GAME_IDS.includes(game))return;const win=net>0;this.data.stats.rounds++;if(NEW_GAME_IDS.includes(game))this.data.stats.newGames++;this.addRenown(35+Math.floor(wager/650)+(win?55:0));this.addDistrict(game,22+Math.floor(wager/900)+(win?28:0),win);this.addBond(game,wager,win);this.advanceOmen();this.data.keyFragments+=1+(win?1:0)+(cryptoFloat()<(this.omenEffect('key')||0)?5:0);while(this.data.keyFragments>=30){this.data.keyFragments-=30;this.data.keys++;this.app.toast('ETERNAL KEY 完成','鍵片30個が秘庫の鍵になりました。','◇')}if(cryptoFloat()<this.artifactDropChance())this.grantArtifact();this.handleOdysseyRound({game,wager,payout,net,win});this.app.profile.save();this.updateAll();this.syncLeague()}
  startOdyssey(){if(this.odyssey.active)return;const seed=hashNumber(`${Date.now()}-${this.app.profile.data.id}`);Object.assign(this.odyssey,{active:true,runId:`ody-${Date.now()}`,seed,floor:1,lives:3,shields:0,score:0,nodes:[],selected:null,rewardChoices:[],history:[],boons:[]});this.prepareOdysseyNodes();this.app.profile.save();this.render('odyssey');this.app.audio.play('chime')}
  prepareOdysseyNodes(){const floor=this.odyssey.floor,boss=[4,8,12].includes(floor);let seed=(this.odyssey.seed+floor*2654435761)>>>0;const available=shuffled(ALL_GAME_IDS).slice(0,3);this.odyssey.nodes=available.map((game,i)=>{seed=(seed*1664525+1013904223)>>>0;const type=boss?'win':['play','win','wager'][seed%3];return{id:`${floor}-${i}-${game}`,game,type,target:type==='wager'?Math.min(10000,500+floor*500):1,boss,icon:GAME_ICONS[game]}});this.odyssey.selected=null}
  selectOdysseyNode(index){const node=this.odyssey.nodes[index];if(!this.odyssey.active||!node)return;this.odyssey.selected=node;this.app.profile.save();this.app.closeModal();this.app.openGame(node.game);this.app.toast(`ODYSSEY FLOOR ${this.odyssey.floor}`,this.conditionText(node),node.icon)}
  conditionText(node){if(node.type==='win')return`${GAME_JP[node.game]}で純利益勝利する`;if(node.type==='wager')return`${GAME_JP[node.game]}で${formatL(node.target)}以上BET`;return`${GAME_JP[node.game]}を1ラウンド完了する`}
  handleOdysseyRound(result){const o=this.odyssey,node=o.selected;if(!o.active||!node||node.game!==result.game)return;let success=node.type==='play'||(node.type==='win'&&result.win)||(node.type==='wager'&&result.wager>=node.target);o.history.push({floor:o.floor,node,success,net:result.net,time:Date.now()});o.bestFloor=Math.max(o.bestFloor||0,o.floor);if(success){let gain=200+o.floor*100+Math.max(0,Math.floor(result.net/50));gain=Math.floor(gain*(1+this.talentEffect('odyssey')+this.omenEffect('odyssey')));o.score+=gain;o.rewardChoices=shuffled(ODYSSEY_BOONS).slice(0,3).map(x=>x.id);o.selected=null;this.app.toast('ODYSSEY CLEAR',`FLOOR ${o.floor} · SCORE +${fmt.format(gain)}`,'♜');setTimeout(()=>{if(o.active)this.open('odyssey')},550)}else{if(o.shields>0){o.shields--;this.app.toast('ODYSSEY SHIELD','敗北によるLIFE減少を無効化しました。','◈')}else o.lives--;o.selected=null;if(o.lives<=0){o.active=false;o.failed++;o.bestScore=Math.max(o.bestScore||0,o.score);this.app.toast('ODYSSEY FAILED',`FLOOR ${o.floor} · SCORE ${fmt.format(o.score)}`,'☾');setTimeout(()=>this.open('odyssey'),500)}else{this.prepareOdysseyNodes();this.app.toast('LIFE LOST',`残りLIFE ${o.lives}`,'♥');setTimeout(()=>this.open('odyssey'),500)}}}
  chooseOdysseyBoon(id){const boon=ODYSSEY_BOONS.find(x=>x.id===id);if(!boon||!this.odyssey.rewardChoices.includes(id))return;boon.apply(this);this.odyssey.boons.push(id);this.odyssey.rewardChoices=[];if(this.odyssey.floor>=12){this.completeOdyssey()}else{this.odyssey.floor++;this.prepareOdysseyNodes();this.app.profile.save();this.render('odyssey')}}
  completeOdyssey(){const o=this.odyssey;const reward=Math.min(12000,Math.floor(4000+o.score*2)),paid=this.app.profile.credit(reward,'odyssey');this.data.keys+=3;this.grantArtifact('mythic',false);o.completed++;o.bestScore=Math.max(o.bestScore||0,o.score);this.data.stats.odysseyClears++;o.active=false;this.app.profile.save();if(paid>0)this.app.bigWin(paid,'PALACE ODYSSEY CONQUERED',`SCORE ${fmt.format(o.score)} · MYTHIC ARTIFACT${paid<reward?' · 残額NOTES':''}`);else this.app.toast('PALACE ODYSSEY CONQUERED',`SCORE ${fmt.format(o.score)} · 報酬LはCROWN NOTESへ変換されました。`,'♛');this.render('odyssey')}
  abandonOdyssey(){if(!this.odyssey.active)return;this.app.confirm('PALACE ODYSSEYを破棄','現在のFLOOR、LIFE、SCORE、BOONを失います。',()=>{this.odyssey.active=false;this.odyssey.failed++;this.app.profile.save();this.app.closeModal();this.open('odyssey')})}
  buyTalent(id){const node=TALENT_NODES.find(x=>x.id===id);if(!node||this.data.renown.points<1)return;const rank=Number(this.data.renown.nodes[id]||0);if(rank>=node.rankMax)return;if(node.requires&&Number(this.data.renown.nodes[node.requires]||0)<1)return;this.data.renown.nodes[id]=rank+1;this.data.renown.points--;this.app.profile.save();this.app.audio.play('chime');this.render('legacy');this.updateAll()}
  receiveLeague(board){if(!Array.isArray(board))return;this.data.league.board=board;const me=board.findIndex(x=>x.id===this.app.profile.data.id);this.data.league.rank=me>=0?me+1:0;if(me>=0){const entry=board[me];Object.assign(this.data.league,{score:entry.score,rounds:entry.rounds,wins:entry.wins,bestReturn:entry.bestReturn})}this.renderLeagueMini();if(this.tab==='league'&&this.app.activeModal?.id==='eternalModal')this.render('league')}
  async syncLeague(){if(!this.app.room?.online||!this.app.room?.room)return;try{const r=await fetch('/api/league/submit',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({room:this.app.room.room})});if(!r.ok)return;const data=await r.json();if(data.week)this.data.league.week=data.week;if(data.league)this.receiveLeague(data.league);this.data.league.lastSync=Date.now();this.app.profile.save()}catch{}}
  open(tab='legacy'){this.tab=tab;this.app.openModal('eternalModal');this.render(tab)}
  render(tab=this.tab){this.tab=tab;this.data.selectedTab=tab;$$('[data-eternal-tab]').forEach(b=>b.classList.toggle('active',b.dataset.eternalTab===tab));const mount=$('#eternalContent');if(!mount)return;if(tab==='legacy')this.renderLegacy(mount);if(tab==='odyssey')this.renderOdyssey(mount);if(tab==='dealers')this.renderDealers(mount);if(tab==='artifacts')this.renderArtifacts(mount);if(tab==='league')this.renderLeague(mount);this.app.profile.save()}
  renderLegacy(mount){const r=this.data.renown,need=this.renownNeed();mount.innerHTML=`<div class="legacy-hero"><div class="legacy-crown"><i>♛</i><span>${r.level}</span></div><div><p class="eyebrow">PALACE RENOWN</p><h3>永夜王名 Lv.${r.level}</h3><p>全18ゲーム、遠征、PvP、収集を通じて宮殿内の名声が上昇します。</p><div class="legacy-xp"><span>${fmt.format(r.xp)} / ${fmt.format(need)} XP</span><em><u style="width:${clamp(r.xp/need*100,0,100)}%"></u></em></div></div><strong>${r.points}<small>ABILITY POINTS</small></strong></div><div class="district-grid">${DISTRICTS.map(d=>{const s=this.data.districts[d.id],n=this.districtNeed(s.level);return`<div><i>${d.icon}</i><span><small>${d.jp}</small><b>${d.name}</b><em><u style="width:${clamp(s.xp/n*100,0,100)}%"></u></em></span><strong>Lv.${s.level}</strong></div>`}).join('')}</div><div class="talent-board">${TALENT_BRANCHES.map(branch=>`<section><header><i>${branch.icon}</i><span><small>${branch.jp}</small><b>${branch.name}</b></span></header><div>${TALENT_NODES.filter(x=>x.branch===branch.id).map(node=>{const rank=Number(r.nodes[node.id]||0),locked=node.requires&&!r.nodes[node.requires];return`<button data-talent="${node.id}" class="${rank?'learned':''} ${locked?'locked':''}" type="button" ${rank>=3||locked||r.points<1?'disabled':''}><i>${node.index+1}</i><span><b>${rank||locked?'':node.index===0?node.name:'？？？'}${rank?node.name:''}</b><small>${locked?'前段階を開放':rank?`${node.effect.toUpperCase()} +${Math.round(node.amount*100)}% / RANK`:'1 POINTで開放'}</small></span><strong>${rank} / 3</strong></button>`}).join('')}</div></section>`).join('')}</div>`;$$('[data-talent]',mount).forEach(b=>b.addEventListener('click',()=>this.buyTalent(b.dataset.talent)))}
  renderOdyssey(mount){const o=this.odyssey;if(!o.active){mount.innerHTML=`<div class="odyssey-intro"><div class="odyssey-map-art"><i></i><i></i><i></i><b>♜</b></div><p class="eyebrow">ROGUELITE PALACE RUN</p><h3>12階の運命を踏破せよ</h3><p>毎階3つのテーブルから進路を選択。条件を達成してBOONを獲得し、4・8・12階のBOSS TABLEを突破します。失敗するとLIFEを失いますが、RUNごとに経路は変化します。</p><div class="odyssey-record"><span><small>BEST FLOOR</small><b>${o.bestFloor||0}</b></span><span><small>BEST SCORE</small><b>${fmt.format(o.bestScore||0)}</b></span><span><small>CLEARS</small><b>${o.completed||0}</b></span></div><button id="odysseyStart" class="primary-cta" type="button"><span>新しい遠征を始める</span><i>BEGIN PALACE ODYSSEY</i></button></div>`;$('#odysseyStart',mount).addEventListener('click',()=>this.startOdyssey());return}if(o.rewardChoices?.length){mount.innerHTML=`<div class="odyssey-reward"><p class="eyebrow">FLOOR ${o.floor} CLEARED</p><h3>一つのBOONを選ぶ</h3><div>${o.rewardChoices.map(id=>{const b=ODYSSEY_BOONS.find(x=>x.id===id);return`<button data-ody-boon="${id}" type="button"><i>${b.icon}</i><b>${b.name}</b><small>${b.desc}</small></button>`}).join('')}</div><p>SCORE ${fmt.format(o.score)} · LIFE ${o.lives} · SHIELD ${o.shields}</p></div>`;$$('[data-ody-boon]',mount).forEach(b=>b.addEventListener('click',()=>this.chooseOdysseyBoon(b.dataset.odyBoon)));return}mount.innerHTML=`<div class="odyssey-head"><div><p class="eyebrow">RUN ${escapeHtml(o.runId.slice(-6).toUpperCase())}</p><h3>FLOOR ${o.floor} / 12</h3><p>${[4,8,12].includes(o.floor)?'BOSS TABLE — 勝利だけが道を開く':'3つの運命から進路を選択'}</p></div><div class="odyssey-vitals"><span>♥ ${o.lives}</span><span>◈ ${o.shields}</span><span>✦ ${fmt.format(o.score)}</span></div></div><div class="odyssey-track">${Array.from({length:12},(_,i)=>`<i class="${i+1<o.floor?'done':i+1===o.floor?'current':[4,8,12].includes(i+1)?'boss':''}"><b>${i+1}</b></i>`).join('')}</div><div class="odyssey-routes">${o.nodes.map((n,i)=>`<button data-ody-node="${i}" type="button"><i>${n.icon}</i><small>${n.boss?'BOSS TABLE':GAME_JP[n.game]}</small><b>${GAME_NAMES[n.game]}</b><p>${this.conditionText(n)}</p><span>${n.type==='win'?'WIN REQUIRED':n.type==='wager'?formatL(n.target):'COMPLETE 1 ROUND'}</span></button>`).join('')}</div><div class="odyssey-footer"><span>BOONS: ${o.boons.length?o.boons.map(id=>ODYSSEY_BOONS.find(x=>x.id===id)?.icon).join(' '):'NONE'}</span><button id="odysseyAbandon" type="button">RUNを破棄</button></div>`;$$('[data-ody-node]',mount).forEach(b=>b.addEventListener('click',()=>this.selectOdysseyNode(Number(b.dataset.odyNode))));$('#odysseyAbandon',mount).addEventListener('click',()=>this.abandonOdyssey())}
  renderDealers(mount){mount.innerHTML=`<div class="dealer-intro"><p class="eyebrow">EIGHT KEEPERS OF THE TABLES</p><h3>卓主との絆</h3><p>担当ゲームを遊ぶとBONDが上昇。会話と物語が段階的に解放されます。抽選確率は変えず、成長・蒐集・演出だけが広がります。</p></div><div class="dealer-grid">${DEALERS.map(d=>{const s=this.data.dealers[d.id],need=this.dealerNeed(s.level),chapter=Math.min(5,Math.ceil(s.level/2));return`<article class="dealer-card level-${s.level}"><div class="dealer-portrait"><i>${d.icon}</i><em></em></div><header><small>${d.name}</small><h4>${d.jp}</h4><strong>BOND ${s.level} / 10</strong></header><p>${s.level>=2?`「${d.quote}」`:'？？？ — もう少し卓を共にすると会話が開く'}</p><div class="dealer-progress"><span>${s.level>=10?'MAX BOND':`${fmt.format(s.xp)} / ${fmt.format(need)}`}</span><em><u style="width:${s.level>=10?100:clamp(s.xp/need*100,0,100)}%"></u></em></div><footer><b>STORY ${chapter} / 5</b><span>${d.games.map(g=>GAME_ICONS[g]).join(' ')}</span></footer></article>`}).join('')}</div>`}
  renderArtifacts(mount){const owned=Object.keys(this.data.artifacts.owned).length;mount.innerHTML=`<div class="artifact-vault-head"><div><p class="eyebrow">48 ETERNAL ARTIFACTS · TOTAL COLLECTION 120</p><h3>永夜秘宝庫</h3><p>8シリーズ×6品。シリーズ完成で最大4,000 L相当とETERNAL KEYを獲得。準備金超過分はCROWN NOTESになります。</p></div><div class="artifact-wallet"><span><i>◇</i><b>${this.data.keys}</b><small>KEYS</small></span><span><i>◆</i><b>${fmt.format(this.data.artifacts.shards)}</b><small>SHARDS</small></span><span><i>✦</i><b>${owned} / 48</b><small>FOUND</small></span></div></div><div class="artifact-actions"><button id="openArtifactVault" class="primary-cta" type="button" ${this.data.keys<1?'disabled':''}><span>秘宝庫を開く · 3 DROPS</span><i>ETERNAL KEY ×1</i></button><button id="craftArtifact" class="glass-button" type="button" ${this.data.artifacts.shards<400||owned>=48?'disabled':''}>400 SHARDSで未所持を錬成</button></div><div class="artifact-set-list">${ARTIFACT_SETS.map(set=>{const items=ETERNAL_ARTIFACTS.filter(x=>x.set===set.id),count=items.filter(x=>this.data.artifacts.owned[x.id]).length;return`<section><header><span><small>${set.name}</small><b>${set.jp}</b></span><strong>${count} / 6</strong></header><div>${items.map(item=>{const got=this.data.artifacts.owned[item.id];return`<article class="artifact-item ${got?'':'locked'} rarity-${item.rarity}"><i>${got?item.icon:'◇'}</i><b>${got?item.name:'？？？'}</b><small>${got?item.rarity.toUpperCase():'SEALED'}</small></article>`}).join('')}</div></section>`}).join('')}</div>`;$('#openArtifactVault',mount)?.addEventListener('click',()=>this.openArtifactVault());$('#craftArtifact',mount)?.addEventListener('click',()=>this.craftArtifact())}
  renderLeague(mount){const board=this.data.league.board||[];mount.innerHTML=`<div class="league-hero"><div class="league-cup">♛</div><div><p class="eyebrow">ROOM NIGHT LEAGUE · ${this.data.league.week}</p><h3>同じROOMの週間ランキング</h3><p>全ゲーム、PvP、遠征でSCOREを獲得。プレイコインの移動や参加費はありません。</p></div><button id="leagueSync" class="glass-button" type="button">SYNC</button></div><div class="league-stats"><span><small>YOUR SCORE</small><b>${fmt.format(this.data.league.score)}</b></span><span><small>RANK</small><b>${this.data.league.rank?`#${this.data.league.rank}`:'OFFLINE'}</b></span><span><small>ROUNDS</small><b>${fmt.format(this.data.league.rounds)}</b></span><span><small>WINS</small><b>${fmt.format(this.data.league.wins)}</b></span></div><div class="league-board">${board.length?board.map((p,i)=>`<div class="${p.id===this.app.profile.data.id?'self':''}"><b>${i+1}</b><i>${escapeHtml(p.glyph||'♛')}</i><span><strong>${escapeHtml(p.name)}</strong><small>${fmt.format(p.rounds||0)} ROUNDS · ${fmt.format(p.wins||0)} WINS</small></span><em>${fmt.format(p.score)} PTS</em></div>`).join(''):'<div class="league-empty">Nodeサーバー版で同じROOMへ入ると、ここにリアルタイム順位が表示されます。</div>'}</div>`;$('#leagueSync',mount).addEventListener('click',()=>this.syncLeague())}
  renderProfile(mount){const r=this.data.renown,owned=Object.keys(this.data.artifacts.owned).length,bonds=Object.values(this.data.dealers).reduce((a,x)=>a+x.level,0);mount.innerHTML=`<div class="profile-expansion-summary"><div><small>PALACE RENOWN</small><strong>Lv.${r.level}</strong></div><div><small>ETERNAL ARTIFACTS</small><strong>${owned} / 48</strong></div><div><small>DEALER BOND TOTAL</small><strong>${bonds} / 80</strong></div></div><div class="stats-grid"><div class="stat-box"><small>ODYSSEY CLEARS</small><strong>${this.odyssey.completed||0}</strong></div><div class="stat-box"><small>BEST ODYSSEY SCORE</small><strong>${fmt.format(this.odyssey.bestScore||0)}</strong></div><div class="stat-box"><small>HOLD'EM WINS</small><strong>${this.data.stats.holdemWins}</strong></div><div class="stat-box"><small>WAR WINS</small><strong>${this.data.stats.warWins}</strong></div><div class="stat-box"><small>BINGOS</small><strong>${this.data.stats.bingos}</strong></div><div class="stat-box"><small>TOWER SUMMITS</small><strong>${this.data.stats.towerSummits}</strong></div><div class="stat-box"><small>SCRATCH WINS</small><strong>${this.data.stats.scratchWins}</strong></div><div class="stat-box"><small>LEAGUE SCORE</small><strong>${fmt.format(this.data.league.score)}</strong></div></div><button id="profileOpenEternal" class="primary-cta" type="button"><span>永夜王冠庁を開く</span><i>PALACE LEGACY</i></button>`;$('#profileOpenEternal',mount)?.addEventListener('click',()=>{this.app.closeModal();this.open('legacy')})}
  renderLeagueMini(){const board=this.data.league.board||[];const mount=$('#leaguePodium');if(!mount)return;mount.innerHTML=board.length?board.slice(0,3).map((p,i)=>`<div><b>${i+1}</b><i>${escapeHtml(p.glyph||'♛')}</i><span>${escapeHtml(p.name)}</span><strong>${fmt.format(p.score)}</strong></div>`).join(''):'<span>同じROOMでプレイすると順位を同期</span>';$('#leagueSelfScore').textContent=fmt.format(this.data.league.score);$('#leagueSelfRank').textContent=this.data.league.rank?`#${this.data.league.rank}`:'#—'}
  updateAll(){if(!$('#eternalRibbon'))return;const r=this.data.renown,need=this.renownNeed();$('#renownRibbon').textContent=`Lv.${r.level} · ${r.points} PT`;$('#renownRibbonFill').style.width=`${clamp(r.xp/need*100,0,100)}%`;$('#odysseyRibbon').textContent=this.odyssey.active?`FLOOR ${this.odyssey.floor} · ♥${this.odyssey.lives}`:'READY';const avg=Math.floor(Object.values(this.data.dealers).reduce((a,x)=>a+x.level,0)/DEALERS.length);$('#bondRibbon').textContent=`AVG BOND ${avg}`;$('#artifactRibbon').textContent=`${Object.keys(this.data.artifacts.owned).length} / 48 · KEY ${this.data.keys}`;$('#leagueRibbon').textContent=`${fmt.format(this.data.league.score)} PTS`;const omen=this.omen();$('#eternalOmenIcon').textContent=omen?.icon||'✦';$('#eternalOmenName').textContent=omen?`${omen.jp} · ${omen.name}`:`次の大兆候まで ${this.data.omen.nextIn} ROUND`;$('#eternalOmenDesc').textContent=omen?.desc||'成長、蒐集、遠征、リーグを強化する特別な夜。';$('#eternalOmenRounds').textContent=omen?this.data.omen.remaining:this.data.omen.nextIn;$('#eternalOmenBar').classList.toggle('active',Boolean(omen));this.renderLeagueMini()}
}

